// Get AI content safely
let content = $input.first().json?.choices?.[0]?.message?.content ?? "";

// If the model already returned an object (rare), return it
if (content && typeof content === "object") {
  return [{ json: content }];
}

// Normalize to string
content = String(content ?? "").trim();

// Remove ALL markdown code fences anywhere (```json ... ``` or ``` ... ```)
content = content.replace(/```[\w-]*\s*/g, "");
content = content.replace(/```/g, "");
content = content.trim();

// Helper: extract the most likely JSON object by slicing from first "{" to last "}"
function extractJsonObjectString(txt) {
  const first = txt.indexOf("{");
  const last = txt.lastIndexOf("}");
  if (first === -1 || last === -1 || last <= first) return "";
  return txt.slice(first, last + 1).trim();
}

function sanitize(txt) {
  return txt
    .replace(/[\u201C\u201D]/g, '"')     // smart double quotes
    .replace(/[\u2018\u2019]/g, "'")     // smart single quotes
    .replace(/\u00A0/g, " ")             // non breaking space
    .replace(/,\s*([}\]])/g, "$1")       // trailing comma before } or ]
    .trim();
}

function tryParseJson(txt) {
  // Attempt 1: parse as is
  try {
    return JSON.parse(txt);
  } catch (_) {}

  // Attempt 2: sanitize then parse
  let t = sanitize(txt);
  try {
    return JSON.parse(t);
  } catch (_) {}

  // Attempt 3: extract { ... } from full text, sanitize, parse
  const extracted = extractJsonObjectString(t);
  if (extracted) {
    try {
      return JSON.parse(extracted);
    } catch (_) {}
  }

  // Attempt 4: last resort, try extracting from original content (before sanitize)
  const extracted2 = extractJsonObjectString(txt);
  if (extracted2) {
    try {
      return JSON.parse(sanitize(extracted2));
    } catch (_) {}
  }

  // If everything fails, throw with context
  const preview = (txt || "").slice(0, 500);
  throw new Error("Could not parse JSON. Preview: " + preview);
}

// If empty, fail gracefully
if (!content) {
  return [{
    json: {
      parse_ok: false,
      error: "Empty AI content",
      raw_content: content,
    }
  }];
}

try {
  const obj = tryParseJson(content);
  return [{ json: obj }];
} catch (e) {
  // Return debug payload so you can see exactly what broke in n8n
  return [{
    json: {
      parse_ok: false,
      error: String(e?.message || e),
      raw_content: content,
    }
  }];
}

const item = $input.item;

const content = item.json.choices[0].message.content.trim();
let txt = content
  .replace(/^```[\s\S]*?\n/, '')
  .replace(/```$/, '')
  .trim();

const obj = JSON.parse(txt);

return {
  json: obj,
  binary: item.binary,
  pairedItem: { item: 0 },
};

