// n8n Code node
// Extract alleen de e-mailadressen van from en to
function extractEmail(str) {
  if (!str) return "";
  const match = str.match(/<([^>]+)>/);
  if (match) return match[1].trim().toLowerCase();
  const fallback = str.match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i);
  return fallback ? fallback[0].trim().toLowerCase() : "";
}

return items.map(item => {
  return {
    json: {
      from: extractEmail(item.json.from),
      to: extractEmail(item.json.to),
    }
  };
});

return items.map(({ json }) => {
  function addrToStr(a) {
    if (!a) return null;
    return a.name ? `${a.name} <${a.address}>` : a.address;
  }

  function normalizeAddrField(field) {
    if (!field) return [];
    if (Array.isArray(field.value)) return field.value.map(addrToStr).filter(Boolean);
    if (typeof field.text === 'string' && field.text.trim()) return [field.text.trim()];
    if (typeof field === 'string' && field.trim()) return [field.trim()];
    if (Array.isArray(field)) return field.map(x => (typeof x === 'string' ? x : addrToStr(x))).filter(Boolean);
    return [];
  }

  // normaliseer ontvangers
  const to  = normalizeAddrField(json.message?.to || json.to);
  const cc  = normalizeAddrField(json.message?.cc || json.cc);
  const bcc = normalizeAddrField(json.message?.bcc || json.bcc);

  json.message = json.message || {};
  json.message.to = to;
  if (cc.length)  json.message.cc  = cc;
  if (bcc.length) json.message.bcc = bcc;

  // idempotency key zonder [object Object]
  const idemParts = [
    json.account_key || '',
    json.message.subject || '',
    to.join(',') || ''
  ];
  json.idempotency_key = idemParts.join('||');

  // optioneel: als je backend liever 1 string 'from' wil:
  // if (!json.message.from && json.message.from_name && json.message.from_email) {
  //   json.message.from = `${json.message.from_name || ''} <${json.message.from_email}>`.trim();
  // }

  // HTML: \n -> <br> als je echt HTML verstuurt
  if (typeof json.message.html === 'string') {
    json.message.html = json.message.html.replace(/\n/g, '<br>');
  }

  return { json };
});

// n8n Code Node - Prepare Single Object Payload (safe + fast)

const store = $items("Get Store Info")[0]?.json ?? {};
const email = $items("Fix Score Parsing1")[0]?.json ?? {};
const orderData = $items("ShopifyCustomerInfo1")[0]?.json ?? {};
const mail = $items("CS-Mailbox@scaleflows.net")[0]?.json ?? {};

const order = orderData?.orders?.[0] ?? {};

const rawBody = email.clean_message ?? "";
const MAX_BODY_CHARS = 12000; // kies wat je flow aankan
const trimmedBody = rawBody.length > MAX_BODY_CHARS ? rawBody.slice(0, MAX_BODY_CHARS) : rawBody;

return [
  {
    json: {
      store_id: store.store_id ?? null,

      customer_email: mail.from?.value?.[0]?.address ?? null,
      language: email.language ?? "en",

      order_id: order.order_number ?? null,
      order_amount: order.total_price ? Number(order.total_price) : null,
      order_status: order.fulfillment_status ?? "unknown",
      product_count: Array.isArray(order.line_items) ? order.line_items.length : 0,
      product_names: Array.isArray(order.line_items) ? order.line_items.map(i => i?.name).filter(Boolean) : [],

      country: order.shipping_address?.country_code ?? null,
      payment_method: Array.isArray(order.payment_gateway_names) ? order.payment_gateway_names[0] ?? null : null,

      category: "general_inquiry",

      email_subject: mail.subject ?? "",
      email_body: trimmedBody.replace(/\n/g, "<br>")
    }
  }
];

