// Haal raw text uit de CS-Mailbox node
const raw =
  $item(0).$node["CS-Mailbox@scaleflows.net"].json.text ||
  $item(0).$node["CS-Mailbox@scaleflows.net"].json.textPlain ||
  "";

// Zoek de bevestigingslink (vf-)
const confirmMatch = raw.match(/https:\/\/mail-settings\.google\.com\/mail\/vf-[^\s]+/i);

// Zoek de annuleerlink (uf-)
const cancelMatch = raw.match(/https:\/\/mail-settings\.google\.com\/mail\/uf-[^\s]+/i);

return [
  {
    json: {
      confirmUrl: confirmMatch ? confirmMatch[0] : null,
      cancelUrl: cancelMatch ? cancelMatch[0] : null,
      // optioneel: debug
      rawPreview: raw.slice(0, 300),
    },
  },
];

// Verwachte input: $input.all()[0].json.conversation_history

const data = $input.all()[0].json.conversation_history || [];

// Sorteer chronologisch (veilig, mocht het ooit DESC zijn)
data.sort((a, b) => new Date(a.created_at) - new Date(b.created_at));

function clean(text) {
  return String(text || "")
    .replace(/\r/g, "")
    .replace(/\n{3,}/g, "\n\n")
    .replace(/\s+/g, " ")
    .trim();
}

const conversationString = data
  .map(item => {
    const customer = clean(item.customer_message);
    const agent = clean(item.agent_reply);

    return `Customer: ${customer}\nAgent: ${agent}`;
  })
  .join("\n\n---\n\n");

return [
  {
    json: {
      conversation_string: conversationString
    }
  }
];

