// Haal de raw OpenAI output text op
const rawText =
  $input.first()?.json?.output?.[0]?.content?.[0]?.text || "";

// Safety: strip code fences + whitespace
const cleaned = rawText
  .replace(/^```json\s*/i, "")
  .replace(/^```\s*/i, "")
  .replace(/```$/i, "")
  .trim();

let parsed;

try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  // Fail-safe fallback
  parsed = {
    intent: "K",
    confidence: 0.0,
    requires_shopify: false,
    requires_human: false,
    parse_error: true,
    raw: cleaned,
  };
}

// Return in a flat structure for Switch usage
return [
  {
    json: {
      intent: parsed.intent || "K",
      confidence: Number(parsed.confidence || 0),
      requires_shopify: Boolean(parsed.requires_shopify),
      requires_human: Boolean(parsed.requires_human),
    },
  },
];

return items.map(item => {
  if (item.json.ai_answer && typeof item.json.ai_answer === "string") {
    item.json.ai_answer = item.json.ai_answer.replace(/\n/g, "<br>");
  }
  return item;
});

